bool check(int arr[], int d, int n, int c)
{
    //Complete this function to check if c cows can be arranged into n stalls with d distance
    int cows = c;
    cows--;
    int prev = arr[0];

    for(int i=1; i<n; i++) {
        if(arr[i] - prev >= d) {
            cows--;
            prev=arr[i];
        }
        if (cows==0) return true;
    }
    return false;
}

